class Solution:
    def minimumCost(self, start, target, specialRoads):
        nodes = [tuple(start), tuple(target)]
        for r in specialRoads:
            nodes.append((r[0], r[1]))
            nodes.append((r[2], r[3]))
        uniq = []
        seen = {}
        for p in nodes:
            if p not in seen:
                seen[p] = len(uniq)
                uniq.append(p)
        n = len(uniq)
        INF = float('inf')
        dist = [[INF] * n for _ in range(n)]
        for i in range(n):
            dist[i][i] = 0
            for j in range(n):
                if i != j:
                    d = abs(uniq[i][0] - uniq[j][0]) + abs(uniq[i][1] - uniq[j][1])
                    if d < dist[i][j]:
                        dist[i][j] = d
        for r in specialRoads:
            i = seen[(r[0], r[1])]
            j = seen[(r[2], r[3])]
            if r[4] < dist[i][j]:
                dist[i][j] = r[4]
        for k in range(n):
            dk = dist[k]
            for i in range(n):
                dik = dist[i][k]
                if dik == INF:
                    continue
                row = dist[i]
                for j in range(n):
                    nd = dik + dk[j]
                    if nd < row[j]:
                        row[j] = nd
        return dist[seen[tuple(start)]][seen[tuple(target)]]

