import heapq

class Solution:
    def minimumCost(self, start: List[int], target: List[int], specialRoads: List[List[int]]) -> int:
        nodes = [tuple(start), tuple(target)]
        for r in specialRoads:
            nodes.append((r[0], r[1]))
            nodes.append((r[2], r[3]))
        uniq = []
        index = {}
        for p in nodes:
            if p not in index:
                index[p] = len(uniq)
                uniq.append(p)
        n = len(uniq)
        adj = [[] for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i != j:
                    d = abs(uniq[i][0] - uniq[j][0]) + abs(uniq[i][1] - uniq[j][1])
                    adj[i].append((j, d))
        for r in specialRoads:
            i = index[(r[0], r[1])]
            j = index[(r[2], r[3])]
            adj[i].append((j, r[4]))
        s = index[tuple(start)]
        t = index[tuple(target)]
        dist = [float('inf')] * n
        dist[s] = 0
        pq = [(0, s)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]:
                continue
            if u == t:
                break
            for v, w in adj[u]:
                nd = d + w
                if nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(pq, (nd, v))
        return dist[t]

