var minimumCost = function(start, target, specialRoads) {
    const key = (x, y) => x + ',' + y;
    const nodes = [[start[0], start[1]], [target[0], target[1]]];
    for (const r of specialRoads) {
        nodes.push([r[0], r[1]]);
        nodes.push([r[2], r[3]]);
    }
    const index = new Map();
    const uniq = [];
    for (const p of nodes) {
        const k = key(p[0], p[1]);
        if (!index.has(k)) {
            index.set(k, uniq.length);
            uniq.push(p);
        }
    }
    const n = uniq.length;
    const adj = Array.from({length: n}, () => []);
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (i !== j) {
                const d = Math.abs(uniq[i][0] - uniq[j][0]) + Math.abs(uniq[i][1] - uniq[j][1]);
                adj[i].push([j, d]);
            }
        }
    }
    for (const r of specialRoads) {
        const i = index.get(key(r[0], r[1]));
        const j = index.get(key(r[2], r[3]));
        adj[i].push([j, r[4]]);
    }
    const s = index.get(key(start[0], start[1]));
    const t = index.get(key(target[0], target[1]));
    const dist = new Array(n).fill(Infinity);
    dist[s] = 0;
    const visited = new Array(n).fill(false);
    for (let iter = 0; iter < n; iter++) {
        let u = -1;
        let best = Infinity;
        for (let i = 0; i < n; i++) {
            if (!visited[i] && dist[i] < best) {
                best = dist[i];
                u = i;
            }
        }
        if (u === -1) break;
        visited[u] = true;
        if (u === t) break;
        for (const [v, w] of adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }
    return dist[t];
};
